INSERT INTO resources (name, category_id, subcategory, description, address, city, county, state, zip_code, phone, website, hours, accepts_uninsured, sliding_scale, medicaid, medicare, private_insurance, walk_ins_welcome, appointments, telehealth, cost_free, cost_estimate_min, cost_estimate_max, languages, accessibility, services, specialties, audiences, rating, photo_url, source) VALUES
('988 Suicide and Crisis Lifeline Washington', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, confidential, three-digit phone number connecting callers to trained crisis counselors via phone, text, or chat. 24/7/365 support for anyone thinking about suicide, experiencing a mental health crisis, or worried about a loved one.', '', 'Statewide', 'Statewide', 'WA', '', '988', 'https://wa988.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{TTY}', '{"Crisis intervention","suicide prevention","emotional support"}', '{Suicide prevention,Crisis intervention}', '{Adults,Adolescents,Veterans,LGBTQ+}', 5.0, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('King County Regional Crisis Line', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'King County 988 and Regional Crisis Line providing immediate, anonymous, and confidential assistance for people experiencing emotional distress or mental health crisis. Staffed 24/7.', '', 'Statewide', 'King', 'WA', '', '866-427-4747', 'https://crisisconnections.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{TTY,"interpreter services",Interpreter,"interpreter services"}', '{"Crisis intervention","suicide prevention","emotional support","resource referrals"}', '{Crisis intervention,Suicide prevention}', '{Adults,Adolescents}', 5.0, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Washington Recovery Help Line', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Statewide, 24-hour service providing emotional support and treatment referrals for substance use, problem gambling, and mental health disorders. Operated by Crisis Connections.', '', 'Statewide', 'Statewide', 'WA', '', '866-789-1511', 'https://www.warecoveryhelpline.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{TTY}', '{"Emotional support","treatment referrals","substance use support","gambling support"}', '{Substance use,"Problem gambling",Mental health}', '{Adults,Adolescents}', 5.0, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Teen Link', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, anonymous, and confidential helpline by teens, for teens in Washington State. Calls answered by trained teen volunteers. Available 6pm to 10pm daily.', '', 'Statewide', 'Statewide', 'WA', '', '866-TEENLINK', 'https://crisisconnections.org/programs/teen-link', '{"mon":"18:00-22:00","tue":"18:00-22:00","wed":"18:00-22:00","thu":"18:00-22:00","fri":"18:00-22:00","sat":"18:00-22:00","sun":"18:00-22:00"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{TTY}', '{"Teen crisis support","suicide prevention","emotional support","school stress support"}', '{Suicide prevention,Teen support}', '{Adolescents,Youth}', 5.0, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Veterans Crisis Line', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, confidential, 24/7/365 crisis support connecting Veterans, service members, and their families with qualified VA responders. Dial 988 then press 1, or text 838255.', '', 'Statewide', 'Statewide', 'WA', '', '988', 'https://www.veteranscrisisline.net', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish}', '{TTY}', '{"Crisis support","suicide prevention","emotional support","VA connection"}', '{Suicide prevention,Crisis intervention,Veterans}', '{Adults,Adolescents,Veterans,"Military families"}', 5.0, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Native and Strong Lifeline', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'The nations first 988 crisis line designed by and for Indigenous people. Connects callers with Native crisis counselors who provide culturally informed support. Dial 988 then press 4.', '', 'Statewide', 'Statewide', 'WA', '', '988', 'https://nativeandstrong.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English}', '{TTY}', '{"Culturally informed crisis support","suicide prevention","emotional support","Native counseling"}', '{Suicide prevention,Crisis intervention,"Indigenous communities"}', '{Adults,Adolescents,"Indigenous peoples"}', 5.0, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('WA 211 Information and Referral', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'The only statewide helpline in Washington with live, knowledgeable people on the phone. Free, confidential, multilingual resource connecting people to utility assistance, food, housing, healthcare, and more. Available 24/7.', '', 'Statewide', 'Statewide', 'WA', '', '211', 'https://wa211.org', '{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}'::jsonb, true, false, false, false, false, true, false, true, true, 0, 0, '{English,Spanish,Russian,Vietnamese,Korean,Tagalog}', '{TTY}', '{"Resource referrals","utility assistance","food referrals","housing referrals","healthcare referrals","elder care","childcare referrals","mental health referrals"}', '{"Information and referral"}', '{Adults,Families,Seniors,Children,Youth,Immigrants,Veterans}', 4.9, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sundown M Ranch', (SELECT id FROM resource_categories WHERE slug='substance-use'), 'Residential', 'Withdrawal management (detox), residential/inpatient SUD treatment for adults and youth (ages 12+), outpatient treatment, integrated medical services, and family programming. Typical stay 28-45 days.', '2280 State Route 821', 'Yakima', 'Yakima', 'WA', '98901', '(509) 457-0990', 'https://sundown.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,"ADA parking"}', '{"Detox/withdrawal management","residential treatment","outpatient treatment","family programming","medical services"}', '{Alcohol use disorder,"Opioid use disorder","Stimulant use","Co-occurring disorders",MAT}', '{Adults,Families,Young adults,Adolescents}', 4.4, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Lakeside-Milam Recovery Centers - Kirkland', (SELECT id FROM resource_categories WHERE slug='substance-use'), 'Residential', 'CARF-accredited, ASAM-certified. Inpatient residential treatment (4-5 week program) with in-house detox/withdrawal management, medication-assisted treatment (MAT), outpatient/IOP at 9 western WA campuses, family programs, and mental health services.', '6725 116th Ave NE', 'Kirkland', 'King', 'WA', '98033', '(425) 822-5095', 'https://lakesidemilam.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,"ADA parking"}', '{"Inpatient residential treatment","detox/withdrawal management","MAT","outpatient/IOP","family programs","mental health services"}', '{Alcohol use disorder,"Opioid use disorder","Stimulant use","Co-occurring disorders",MAT}', '{Adults,Young adults}', 4.3, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Spokane Treatment and Recovery Services (STARS)', (SELECT id FROM resource_categories WHERE slug='substance-use'), 'Outpatient', 'Non-profit behavioral health agency serving the Inland Northwest since 1980. SUD and mental health assessments, sobering/triage, withdrawal management, residential programs, co-occurring intensive outpatient, and case management. 24/7 SUD services.', '105 W 3rd Ave', 'Spokane', 'Spokane', 'WA', '99201', '(509) 570-7250', 'https://spokanerecovery.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,"ADA parking"}', '{"SUD assessments","sobering/triage","withdrawal management","residential programs","outpatient treatment","case management"}', '{Alcohol use disorder,"Opioid use disorder","Stimulant use","Co-occurring disorders"}', '{Adults,Young adults,Women,Men}', 4.3, 'https://images.pexels.com/photos/3759079/pexels-photo-3759079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Pioneer Counseling - Seattle', (SELECT id FROM resource_categories WHERE slug='substance-use'), 'Outpatient', 'Nonprofit serving justice-involved individuals. Outpatient SUD counseling, co-occurring residential treatment (16-bed dual-diagnosis facility), MAT, detox/stabilization services, housing, and employment/training.', '901 Rainier Ave S', 'Seattle', 'King', 'WA', '98144', '(206) 768-1990', 'https://pioneerhumanservices.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,"ADA parking"}', '{"Outpatient SUD counseling","co-occurring residential treatment","MAT","detox/stabilization","housing support","employment training"}', '{Substance use,"Co-occurring disorders",Alcohol use disorder,"Opioid use disorder"}', '{Adults,"Justice-involved"}', 4.2, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Royal Life Centers at Puget Sound', (SELECT id FROM resource_categories WHERE slug='substance-use'), 'Residential', 'Medical detox, residential inpatient treatment for drug and alcohol addiction, individual/group therapy, dual diagnosis care, and aftercare.', '1723 Bonney Ave', 'Sumner', 'Pierce', 'WA', '98390', '(844) 962-2772', 'https://pugetsoundrecoverycenters.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English}', '{wheelchair,"ADA parking"}', '{"Medical detox","residential treatment","individual/group therapy","dual diagnosis care","aftercare"}', '{Alcohol use disorder,"Opioid use disorder","Stimulant use","Co-occurring disorders"}', '{Adults,Young adults}', 4.1, 'https://images.pexels.com/photos/3759079/pexels-photo-3759079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Free by the Sea', (SELECT id FROM resource_categories WHERE slug='substance-use'), 'Residential', 'CARF-accredited dual-diagnosis treatment center on a 5-acre campus. Residential inpatient, PHP, IOP, MAT, and gambling addiction track.', '25517 Park Ave', 'Ocean Park', 'Pacific', 'WA', '98640', '(360) 777-7050', 'https://freebythesea.com', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,"ADA parking"}', '{"Residential treatment","PHP","IOP","MAT","dual-diagnosis","gambling addiction track"}', '{Alcohol use disorder,"Opioid use disorder","Stimulant use","Co-occurring disorders","Gambling"}', '{Adults,Young adults}', 4.3, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('SRHD Opioid Treatment Program', (SELECT id FROM resource_categories WHERE slug='substance-use'), 'MAT', 'State- and federally-accredited Opioid Treatment Program providing MAT with methadone and buprenorphine, individual and group counseling, and on-site mental health counseling.', '312 W 8th Ave', 'Spokane', 'Spokane', 'WA', '99204', '(509) 324-1420', 'https://srhd.org/programs-and-services/opioid-treatment-program', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,"ADA parking"}', '{"MAT (methadone)","MAT (buprenorphine)","individual counseling","group counseling","mental health counseling","case management"}', '{Opioid use disorder,"MAT/MOUD",Co-occurring disorders}', '{Adults}', 4.5, 'https://images.pexels.com/photos/3759079/pexels-photo-3759079.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Cedar Wellness Center', (SELECT id FROM resource_categories WHERE slug='substance-use'), 'MAT', 'Opioid Treatment Program (methadone clinic) with MAT for fentanyl, heroin, prescription opioids, and other substance use. Integrated mental health services, limited primary care for enrolled patients.', '503 E 26th St', 'Tacoma', 'Pierce', 'WA', '98421', '(253) 881-7001', 'https://cw.health', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"9:00-13:00","sun":"Closed"}'::jsonb, true, true, true, true, true, true, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,"ADA parking"}', '{"MAT (methadone)","MAT (buprenorphine)","integrated mental health","limited primary care","individual therapy","group therapy","patient navigation"}', '{Opioid use disorder,"Methamphetamine use","Benzodiazepine use","Alcohol use","Cocaine use","Co-occurring disorders"}', '{Adults,Young adults}', 4.2, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified')
